parameters.body:
={
  "contents": [{
    "parts": [{
      "text": "You are an empathetic clinical assistant for Dr. Sayuj, a Neurosurgeon. Write a short, warm, personalized email message to a patient thanking them for their trust after a positive post-op outcome, and kindly asking them to leave a review on Google My Business.

Patient Name: {{$node["Webhook Trigger"].json["body"]["patientName"]}}
Procedure/Condition: {{$node["Webhook Trigger"].json["body"]["procedure"]}}

Generate strictly valid JSON with these fields:
- subject: An engaging email subject line.
- email_body_html: The HTML body of the email. Include a placeholder '[GMB_LINK]' where the review link will go. Be empathetic, acknowledge their specific procedure, and explain how reviews help other patients find the right neurosurgical care."
    }]
  }]
}

parameters.functionCode:
const geminiResp = items[0].json.candidates[0].content.parts[0].text;
// Remove markdown code blocks if present
const cleanJson = geminiResp.replace(/```json/g, '').replace(/```/g, '').trim();
let emailContent = {};
try {
  emailContent = JSON.parse(cleanJson);
  // Inject the actual GMB link
  emailContent.email_body_html = emailContent.email_body_html.replace('[GMB_LINK]', '<a href="https://g.page/r/drsayuj/review">Leave a Review for Dr. Sayuj on Google</a>');
} catch (e) {
  emailContent = { subject: 'Thank you from Dr. Sayuj', email_body_html: '<p>Dear Patient, thank you for your trust. Please <a href="https://g.page/r/drsayuj/review">leave us a review</a> to help others.</p>' };
}

return [{
  json: {
    ...items[0].json,
    emailContent
  }
}];
